package com.samudhra.certificates.controller;
import com.samudhra.certificates.dto.*; import com.samudhra.certificates.repository.UserRepository; import com.samudhra.certificates.security.JwtService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/auth") public class AuthController {private final UserRepository users;private final PasswordEncoder encoder;private final JwtService jwt;public AuthController(UserRepository u,PasswordEncoder e,JwtService j){users=u;encoder=e;jwt=j;} @PostMapping("/login") public ApiResponse<AuthDtos.LoginResponse> login(@Valid @RequestBody AuthDtos.LoginRequest input){var user=users.findByEmail(input.email()).orElseThrow(()->new IllegalArgumentException("Invalid email or password"));if(!encoder.matches(input.password(),user.getPasswordHash()))throw new IllegalArgumentException("Invalid email or password");return ApiResponse.ok(new AuthDtos.LoginResponse(jwt.issue(user.getEmail(),user.getRole()),user.getId(),user.getName(),user.getEmail(),user.getRole()));}}
